package predicate

import (
	"sigs.k8s.io/controller-runtime/pkg/event"
	"sigs.k8s.io/controller-runtime/pkg/predicate"
	v1 "sigs.k8s.io/gateway-api/apis/v1"
)

// GatewayClassPredicate implements a predicate function based on the controllerName of a GatewayClass.
// This predicate will skip events for GatewayClasses that don't reference this controller.
type GatewayClassPredicate struct {
	predicate.Funcs
	ControllerName string
}

// Create implements default CreateEvent filter for validating a GatewayClass controllerName.
func (gcp GatewayClassPredicate) Create(e event.CreateEvent) bool {
	if e.Object == nil {
		return false
	}

	gc, ok := e.Object.(*v1.GatewayClass)
	if !ok {
		return false
	}

	return string(gc.Spec.ControllerName) == gcp.ControllerName
}

// Update implements default UpdateEvent filter for validating a GatewayClass controllerName.
func (gcp GatewayClassPredicate) Update(e event.UpdateEvent) bool {
	if e.ObjectOld != nil {
		gcOld, ok := e.ObjectOld.(*v1.GatewayClass)
		if ok && string(gcOld.Spec.ControllerName) == gcp.ControllerName {
			return true
		}
	}

	if e.ObjectNew != nil {
		gcNew, ok := e.ObjectNew.(*v1.GatewayClass)
		if ok && string(gcNew.Spec.ControllerName) == gcp.ControllerName {
			return true
		}
	}

	return false
}

// Delete implements default DeleteEvent filter for validating a GatewayClass controllerName.
func (gcp GatewayClassPredicate) Delete(e event.DeleteEvent) bool {
	if e.Object == nil {
		return false
	}

	gc, ok := e.Object.(*v1.GatewayClass)
	if !ok {
		return false
	}

	return string(gc.Spec.ControllerName) == gcp.ControllerName
}

package events

import (
	"k8s.io/apimachinery/pkg/types"
	"sigs.k8s.io/controller-runtime/pkg/client"

	ngftypes "github.com/nginx/nginx-gateway-fabric/v2/internal/framework/types"
)

// EventBatch is a batch of events to be handled at once.
type EventBatch []any

// UpsertEvent represents upserting a resource.
type UpsertEvent struct {
	// Resource is the resource that is being upserted.
	Resource client.Object
}

// DeleteEvent representing deleting a resource.
type DeleteEvent struct {
	// Type is the resource type. For example, if the event is for *v1.HTTPRoute, pass &v1.HTTPRoute{} as Type.
	Type ngftypes.ObjectType
	// NamespacedName is the namespace & name of the deleted resource.
	NamespacedName types.NamespacedName
}

// WAFBundleReconcileEvent is injected by the WAF poller manager when a bundle that was previously
// unavailable has been successfully fetched for the first time.
// It signals the event handler to re-reconcile the affected policy so the Gateway config push proceeds.
type WAFBundleReconcileEvent struct {
	// PolicyNsName is the namespace/name of the WAFPolicy whose bundle is now available.
	PolicyNsName types.NamespacedName
}

package types //nolint:revive, nolintlint // ignoring “meaningless package name” and the unused-nolint warning

import "sigs.k8s.io/controller-runtime/pkg/client"

// ObjectType is used when we only care about the type of client.Object.
// The fields of the client.Object may be empty.
type ObjectType client.Object

// Fields used for communication with the EndpointPicker service when using the Inference Extension.
const (
	// EPPEndpointHostHeader is the HTTP header used to specify the EPP endpoint host.
	EPPEndpointHostHeader = "X-EPP-Host"
	// EPPEndpointPortHeader is the HTTP header used to specify the EPP endpoint port.
	EPPEndpointPortHeader = "X-EPP-Port"
	// GoShimPort is the default port for the Go EPP shim server to listen on. If collisions become a problem,
	// we can make this configurable via the NginxProxy resource.
	GoShimPort = 54800 // why 54800? Sum "nginx" in ASCII and multiply by 100.
)

package predicate

import (
	appsv1 "k8s.io/api/apps/v1"
	"sigs.k8s.io/controller-runtime/pkg/event"
	"sigs.k8s.io/controller-runtime/pkg/predicate"

	"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/controller"
)

// AnnotationPredicate implements a predicate function based on the Annotation.
//
// This predicate will skip the following events:
// 1. Create events that do not contain the Annotation.
// 2. Update events where the Annotation value has not changed.
type AnnotationPredicate struct {
	predicate.Funcs
	Annotation string
}

// Create filters CreateEvents based on the Annotation.
func (ap AnnotationPredicate) Create(e event.CreateEvent) bool {
	if e.Object == nil {
		return false
	}

	_, ok := e.Object.GetAnnotations()[ap.Annotation]
	return ok
}

// Update filters UpdateEvents based on the Annotation.
func (ap AnnotationPredicate) Update(e event.UpdateEvent) bool {
	if e.ObjectOld == nil || e.ObjectNew == nil {
		// this case should not happen
		return false
	}

	oldAnnotationVal := e.ObjectOld.GetAnnotations()[ap.Annotation]
	newAnnotationVal := e.ObjectNew.GetAnnotations()[ap.Annotation]

	return oldAnnotationVal != newAnnotationVal
}

// RestartDeploymentAnnotationPredicate skips update events if they are due to a rolling restart.
// This type of event is triggered by adding an annotation to the deployment's PodSpec.
// This is used by the provisioner to ensure it allows for rolling restarts of the nginx deployment
// without reverting the annotation and deleting the new pod(s). Otherwise, if a user changes
// the nginx deployment, we want to see that event so we can revert it back to the configuration
// that we expect it to have.
type RestartDeploymentAnnotationPredicate struct {
	predicate.Funcs
}

// Update filters UpdateEvents based on if the annotation is present or changed.
func (RestartDeploymentAnnotationPredicate) Update(e event.UpdateEvent) bool {
	if e.ObjectOld == nil || e.ObjectNew == nil {
		// this case should not happen
		return false
	}

	depOld, ok := e.ObjectOld.(*appsv1.Deployment)
	if !ok {
		return false
	}

	depNew, ok := e.ObjectNew.(*appsv1.Deployment)
	if !ok {
		return false
	}

	oldVal, oldExists := depOld.Spec.Template.Annotations[controller.RestartedAnnotation]

	if newVal, ok := depNew.Spec.Template.Annotations[controller.RestartedAnnotation]; ok {
		if !oldExists || newVal != oldVal {
			return false
		}
	}

	return true
}

package predicate

import (
	"fmt"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	k8spredicate "sigs.k8s.io/controller-runtime/pkg/predicate"
)

// NginxLabelPredicate returns a predicate that only matches resources with the nginx labels.
func NginxLabelPredicate(selector metav1.LabelSelector) k8spredicate.Predicate {
	labelPredicate, err := k8spredicate.LabelSelectorPredicate(selector)
	if err != nil {
		panic(fmt.Sprintf("error creating label selector: %v", err))
	}

	return labelPredicate
}

package controller

import (
	"context"

	"sigs.k8s.io/controller-runtime/pkg/client"
)

//counterfeiter:generate . Getter

// Getter gets a resource from the k8s API.
// It allows us to mock the client.Reader.Get method.
type Getter interface {
	// Get is from client.Reader.
	Get(ctx context.Context, key client.ObjectKey, obj client.Object, opts ...client.GetOption) error
}

package controller

// The following labels are added to each nginx resource created by the control plane.
const (
	GatewayLabel      = "gateway.networking.k8s.io/gateway-name"
	AppNameLabel      = "app.kubernetes.io/name"
	AppInstanceLabel  = "app.kubernetes.io/instance"
	AppManagedByLabel = "app.kubernetes.io/managed-by"
)

// RestartedAnnotation is added to a Deployment or DaemonSet's PodSpec to trigger a rolling restart.
const RestartedAnnotation = "kubectl.kubernetes.io/restartedAt"

package controller

import (
	"crypto/sha256"
	"encoding/hex"
	"strings"
)

const (
	// inferencePoolServiceSuffix is the suffix of the headless Service name for an InferencePool.
	inferencePoolServiceSuffix = "pool-svc"
	MaxServiceNameLen          = 63
	hashLen                    = 8
)

// CreateNginxResourceName creates the base resource name for all nginx resources
// created by the control plane.
func CreateNginxResourceName(prefix, suffix string) string {
	return truncateAndHashName(prefix, suffix)
}

// CreateInferencePoolServiceName creates the name for a headless Service that
// we create for an InferencePool.
func CreateInferencePoolServiceName(name string) string {
	return truncateAndHashName(name, inferencePoolServiceSuffix)
}

// truncateAndHashName truncates the input name to fit within maxLen,
// appending a hash for uniqueness if needed.
func truncateAndHashName(name string, suffix string) string {
	sep := "-"
	full := name + sep + suffix
	if len(full) <= MaxServiceNameLen {
		return full
	}

	// Always include the suffix, truncate name as needed
	hash := sha256.Sum256([]byte(full))
	hashStr := hex.EncodeToString(hash[:])[:hashLen]
	maxNameLen := MaxServiceNameLen - (len(sep) * 2) - hashLen - len(suffix)
	truncName := name
	if len(name) > maxNameLen {
		truncName = name[:maxNameLen]
	}

	// Remove trailing dashes to avoid double-dash when separator is added
	truncName = strings.TrimRight(truncName, sep)

	return truncName + sep + hashStr + sep + suffix
