func TestGatewayClassPredicate(t *testing.T) {
	t.Parallel()
	g := NewWithT(t)

	p := GatewayClassPredicate{ControllerName: "nginx-ctlr"}

	gc := &v1.GatewayClass{
		Spec: v1.GatewayClassSpec{
			ControllerName: "nginx-ctlr",
		},
	}

	g.Expect(p.Create(event.CreateEvent{Object: gc})).To(BeTrue())
	g.Expect(p.Update(event.UpdateEvent{ObjectNew: gc})).To(BeTrue())
	g.Expect(p.Delete(event.DeleteEvent{Object: gc})).To(BeTrue())

	gc2 := &v1.GatewayClass{
		Spec: v1.GatewayClassSpec{
			ControllerName: "unknown",
		},
	}
	g.Expect(p.Create(event.CreateEvent{Object: gc2})).To(BeFalse())
	g.Expect(p.Update(event.UpdateEvent{ObjectOld: gc, ObjectNew: gc2})).To(BeTrue())
	g.Expect(p.Update(event.UpdateEvent{ObjectOld: gc2, ObjectNew: gc})).To(BeTrue())
	g.Expect(p.Update(event.UpdateEvent{ObjectOld: gc2, ObjectNew: gc2})).To(BeFalse())
	g.Expect(p.Delete(event.DeleteEvent{Object: nil})).To(BeFalse())
	g.Expect(p.Delete(event.DeleteEvent{Object: gc2})).To(BeFalse())
	g.Expect(p.Delete(event.DeleteEvent{Object: &v1.HTTPRoute{}})).To(BeFalse())
}

// Resolve resolves a Service's NamespacedName and ServicePort to a list of Endpoints.
// Returns an error if the Service or ServicePort cannot be resolved.
func (e *ServiceResolverImpl) Resolve(
	ctx context.Context,
	logger logr.Logger,
	svcNsName types.NamespacedName,
	svcPort v1.ServicePort,
	allowedAddressType []discoveryV1.AddressType,
) ([]Endpoint, error) {
	if svcPort.Port == 0 || svcNsName.Name == "" || svcNsName.Namespace == "" {
		panic(fmt.Errorf("expected the following fields to be non-empty: name: %s, ns: %s, port: %d",
			svcNsName.Name, svcNsName.Namespace, svcPort.Port))
	}

	// We list EndpointSlices using the Service Name Index Field we added as an index to the EndpointSlice cache.
	// This allows us to perform a quick lookup of all EndpointSlices for a Service.
	var endpointSliceList discoveryV1.EndpointSliceList
	err := e.reader.List(
		ctx,
		&endpointSliceList,
		client.MatchingFields{index.KubernetesServiceNameIndexField: svcNsName.Name},
		client.InNamespace(svcNsName.Namespace),
	)

	if err != nil || len(endpointSliceList.Items) == 0 {
		return nil, fmt.Errorf("no endpoints found for Service %s", svcNsName)
	}

	return resolveEndpoints(
		logger,
		svcNsName,
		svcPort,
		endpointSliceList,
		initEndpointSetWithCalculatedSize,
		allowedAddressType,
	)
}

